# Usage: ssh_accept_new <user@host> [ssh args...]
# Example: ssh_accept_new testuser@192.168.1.100 "echo hello"
ssh_accept_new() {
    ssh -o ConnectTimeout=10 -o StrictHostKeyChecking=accept-new -o BatchMode=yes "$@"
}

